```typescript
export type EnrolmentState =
  | { status: "empty" }
  | { status: "registered"; id: string; learner: string; course: string }
  | { status: "confirmed"; id: string; learner: string; course: string; confirmedAt: string }
  | { status: "dropped"; id: string; reason: string };

export type EnrolmentCommand =
  | { type: "register"; id: string; learner: string; course: string }
  | { type: "confirm"; at: string }
  | { type: "drop"; at: string; dropDeadline: string; reason: string };

export type EnrolmentEvent =
  | { type: "EnrolmentRegistered"; id: string; learner: string; course: string }
  | { type: "EnrolmentConfirmed"; at: string }
  | { type: "EnrolmentDropped"; reason: string };

export class DomainError extends Error {
  constructor(public readonly code: string) {
    super(code);
    this.name = "DomainError";
  }
}

export interface Decider<C, E, S> {
  readonly initialState: S;
  decide(command: C, state: S): E[];
  evolve(state: S, event: E): S;
}

export const enrolmentDecider: Decider<EnrolmentCommand, EnrolmentEvent, EnrolmentState> = {
  initialState: { status: "empty" },
  decide(command, state) {
    switch (command.type) {
      case "register": {
        if (state.status !== "empty") throw new DomainError("ALREADY_REGISTERED");
        if (command.learner.length === 0) throw new DomainError("LEARNER_REQUIRED");
        return [{ type: "EnrolmentRegistered", id: command.id, learner: command.learner, course: command.course }];
      }
      case "confirm": {
        if (state.status !== "registered") throw new DomainError("NOT_REGISTERED");
        return [{ type: "EnrolmentConfirmed", at: command.at }];
      }
      case "drop": {
        if (state.status === "empty") throw new DomainError("NOTHING_TO_DROP");
        if (state.status === "dropped") throw new DomainError("ALREADY_DROPPED");
        if (state.status === "confirmed" && command.at > command.dropDeadline) {
          throw new DomainError("PAST_DROP_DATE");
        }
        return [{ type: "EnrolmentDropped", reason: command.reason }];
      }
      default: {
        const _never: never = command;
        throw new DomainError("UNKNOWN_COMMAND");
      }
    }
  },
  evolve(state, event) {
    switch (event.type) {
      case "EnrolmentRegistered":
        return { status: "registered", id: event.id, learner: event.learner, course: event.course };
      case "EnrolmentConfirmed":
        if (state.status !== "registered") return state;
        return { status: "confirmed", id: state.id, learner: state.learner, course: state.course, confirmedAt: event.at };
      case "EnrolmentDropped":
        if (state.status === "empty" || state.status === "dropped") return state;
        return { status: "dropped", id: state.id, reason: event.reason };
      default: {
        const _never: never = event;
        return state;
      }
    }
  },
};
```

A Decider is the pure triple (initialState, decide, evolve). `decide` is the only place invariants live: given a command and current state it either returns the events it produces or throws a typed error. `evolve` is a total fold — it never validates, only projects new state from an event. Because both are pure, replaying a stream always yields the same state.

```typescript
export type CourseState =
  | { status: "draft" }
  | { status: "open"; id: string; title: string; capacity: number }
  | { status: "scheduled"; id: string; title: string; capacity: number; starts: string }
  | { status: "closed"; id: string; title: string };

export type CourseCommand =
  | { type: "open"; id: string; title: string; capacity: number }
  | { type: "schedule"; starts: string }
  | { type: "close" };

export type CourseEvent =
  | { type: "CourseOpened"; id: string; title: string; capacity: number }
  | { type: "CourseScheduled"; starts: string }
  | { type: "CourseClosed" };

export class CourseError extends Error {}

export interface Decider<C, E, S> {
  readonly initialState: S;
  decide(c: C, s: S): E[];
  evolve(s: S, e: E): S;
}

export const courseDecider: Decider<CourseCommand, CourseEvent, CourseState> = {
  initialState: { status: "draft" },
  decide(c, s) {
    switch (c.type) {
      case "open":
        if (s.status !== "draft") throw new CourseError("ALREADY_OPEN");
        if (c.capacity <= 0) throw new CourseError("CAPACITY_INVALID");
        return [{ type: "CourseOpened", id: c.id, title: c.title, capacity: c.capacity }];
      case "schedule":
        if (s.status !== "open") throw new CourseError("NOT_OPEN");
        return [{ type: "CourseScheduled", starts: c.starts }];
      case "close":
        if (s.status === "closed" || s.status === "draft") throw new CourseError("CANNOT_CLOSE");
        return [{ type: "CourseClosed" }];
      default: { const _n: never = c; throw new CourseError("UNKNOWN"); }
    }
  },
  evolve(s, e) {
    switch (e.type) {
      case "CourseOpened":
        return { status: "open", id: e.id, title: e.title, capacity: e.capacity };
      case "CourseScheduled":
        if (s.status !== "open") return s;
        return { status: "scheduled", id: s.id, title: s.title, capacity: s.capacity, starts: e.starts };
      case "CourseClosed":
        if (s.status === "draft" || s.status === "closed") return s;
        return { status: "closed", id: s.id, title: s.title };
      default: { const _n: never = e; return s; }
    }
  },
};
