```typescript
export type SubmissionState =
  | { status: "none" }
  | { status: "drafting"; id: string; attachments: ReadonlyArray<string> }
  | { status: "turnedIn"; id: string; attachments: ReadonlyArray<string>; at: string }
  | { status: "retracted"; id: string; reason: string };

export type SubmissionCommand =
  | { type: "start"; id: string }
  | { type: "attach"; filename: string }
  | { type: "turnIn"; at: string }
  | { type: "retract"; reason: string };

export type SubmissionEvent =
  | { type: "SubmissionStarted"; id: string }
  | { type: "AttachmentAttached"; filename: string }
  | { type: "SubmissionTurnedIn"; at: string }
  | { type: "SubmissionRetracted"; reason: string };

export class SubmissionError extends Error {}

export interface Decider<C, E, S> {
  readonly initialState: S;
  decide(c: C, s: S): E[];
  evolve(s: S, e: E): S;
}

export const submissionDecider: Decider<SubmissionCommand, SubmissionEvent, SubmissionState> = {
  initialState: { status: "none" },
  decide(c, s) {
    switch (c.type) {
      case "start":
        if (s.status !== "none") throw new SubmissionError("ALREADY_STARTED");
        return [{ type: "SubmissionStarted", id: c.id }];
      case "attach":
        if (s.status !== "drafting") throw new SubmissionError("NOT_DRAFTING");
        if (c.filename.length === 0) throw new SubmissionError("EMPTY_FILENAME");
        return [{ type: "AttachmentAttached", filename: c.filename }];
      case "turnIn":
        if (s.status !== "drafting") throw new SubmissionError("NOT_DRAFTING");
        if (s.attachments.length === 0) throw new SubmissionError("NO_ATTACHMENTS");
        return [{ type: "SubmissionTurnedIn", at: c.at }];
      case "retract":
        if (s.status !== "turnedIn") throw new SubmissionError("NOT_TURNED_IN");
        return [{ type: "SubmissionRetracted", reason: c.reason }];
      default: { const _n: never = c; throw new SubmissionError("UNKNOWN"); }
    }
  },
  evolve(s, e) {
    switch (e.type) {
      case "SubmissionStarted":
        return { status: "drafting", id: e.id, attachments: [] };
      case "AttachmentAttached":
        if (s.status !== "drafting") return s;
        return { status: "drafting", id: s.id, attachments: [...s.attachments, e.filename] };
      case "SubmissionTurnedIn":
        if (s.status !== "drafting") return s;
        return { status: "turnedIn", id: s.id, attachments: s.attachments, at: e.at };
      case "SubmissionRetracted":
        if (s.status !== "turnedIn") return s;
        return { status: "retracted", id: s.id, reason: e.reason };
      default: { const _n: never = e; return s; }
    }
  },
};
```

Model the thread as a discriminated-union state driven by commands that emit events. `decide` checks invariants (no posting to a closed thread); `evolve` folds each event into the next state.

```typescript
export type DiscussionState =
  | { status: "none" }
  | { status: "open"; id: string; posts: number }
  | { status: "archived"; id: string; posts: number };

export type DiscussionCommand =
  | { type: "open"; id: string; topic: string }
  | { type: "post"; author: string; body: string }
  | { type: "archive"; reason: string };

export type DiscussionEvent =
  | { type: "DiscussionOpened"; id: string; topic: string }
  | { type: "PostAppended"; author: string; body: string }
  | { type: "DiscussionArchived"; reason: string };

export class DiscussionError extends Error {}

export interface Decider<C, E, S> {
  readonly initialState: S;
  decide(c: C, s: S): E[];
  evolve(s: S, e: E): S;
}

export const discussionDecider: Decider<DiscussionCommand, DiscussionEvent, DiscussionState> = {
  initialState: { status: "none" },
  decide(c, s) {
    switch (c.type) {
      case "open":
        if (s.status !== "none") throw new DiscussionError("ALREADY_OPEN");
        return [{ type: "DiscussionOpened", id: c.id, topic: c.topic }];
      case "post":
        if (s.status !== "open") throw new DiscussionError("NOT_OPEN");
        if (c.body.length === 0) throw new DiscussionError("EMPTY_BODY");
        return [{ type: "PostAppended", author: c.author, body: c.body }];
      case "archive":
        if (s.status !== "open") throw new DiscussionError("NOT_OPEN");
        return [{ type: "DiscussionArchived", reason: c.reason }];
      default: { const _n: never = c; throw new DiscussionError("UNKNOWN"); }
    }
  },
  evolve(s, e) {
    switch (e.type) {
      case "DiscussionOpened":
        return { status: "open", id: e.id, posts: 0 };
      case "PostAppended":
        if (s.status !== "open") return s;
        return { status: "open", id: s.id, posts: s.posts + 1 };
      case "DiscussionArchived":
        if (s.status !== "open") return s;
        return { status: "archived", id: s.id, posts: s.posts };
      default: { const _n: never = e; return s; }
    }
  },
};
