```typescript
export type LectureEvent =
  | { type: "LectureScheduled"; id: string; title: string; starts: string }
  | { type: "LearnerCheckedIn"; lectureId: string; learner: string }
  | { type: "LearnerCheckedOut"; lectureId: string; learner: string }
  | { type: "LectureCancelled"; id: string };

export type LectureView = Readonly<{
  id: string;
  title: string;
  starts: string;
  cancelled: boolean;
  present: ReadonlyArray<string>;
}>;

export type LectureBoard = Readonly<{
  lectures: Readonly<Record<string, LectureView>>;
}>;

export const emptyView: LectureBoard = { lectures: {} };

function updateLecture(
  view: LectureBoard,
  id: string,
  mapper: (v: LectureView) => LectureView,
): LectureBoard {
  const current = view.lectures[id];
  if (!current) return view;
  return { lectures: { ...view.lectures, [id]: mapper(current) } };
}

export function project(view: LectureBoard, event: LectureEvent): LectureBoard {
  switch (event.type) {
    case "LectureScheduled":
      return {
        lectures: {
          ...view.lectures,
          [event.id]: { id: event.id, title: event.title, starts: event.starts, cancelled: false, present: [] },
        },
      };
    case "LearnerCheckedIn":
      return updateLecture(view, event.lectureId, (v) =>
        v.present.includes(event.learner) ? v : { ...v, present: [...v.present, event.learner] });
    case "LearnerCheckedOut":
      return updateLecture(view, event.lectureId, (v) => ({
        ...v,
        present: v.present.filter((l) => l !== event.learner),
      }));
    case "LectureCancelled":
      return updateLecture(view, event.id, (v) => ({ ...v, cancelled: true }));
    default: { const _n: never = event; return view; }
  }
}

export function lectureBoardFrom(events: ReadonlyArray<LectureEvent>): LectureBoard {
  return events.reduce(project, emptyView);
}
```

```typescript
export type SyllabusEvent =
  | { type: "SyllabusCreated"; syllabusId: string; title: string }
  | { type: "SyllabusModuleAdded"; syllabusId: string; moduleId: string; name: string }
  | { type: "SyllabusModuleRemoved"; syllabusId: string; moduleId: string }
  | { type: "SyllabusReordered"; syllabusId: string; moduleIds: ReadonlyArray<string> };

export type SyllabusView = Readonly<{
  syllabusId: string;
  title: string;
  modules: ReadonlyArray<Readonly<{ moduleId: string; name: string }>>;
}>;

export function emptyView(syllabusId: string): SyllabusView {
  return { syllabusId, title: "", modules: [] };
}

export function project(view: SyllabusView, event: SyllabusEvent): SyllabusView {
  if (event.syllabusId !== view.syllabusId) return view;
  switch (event.type) {
    case "SyllabusCreated":
      return { syllabusId: view.syllabusId, title: event.title, modules: [] };
    case "SyllabusModuleAdded":
      if (view.modules.some((m) => m.moduleId === event.moduleId)) return view;
      return {
        ...view,
        modules: [...view.modules, { moduleId: event.moduleId, name: event.name }],
      };
    case "SyllabusModuleRemoved":
      return {
        ...view,
        modules: view.modules.filter((m) => m.moduleId !== event.moduleId),
      };
    case "SyllabusReordered": {
      const lookup = new Map(view.modules.map((m) => [m.moduleId, m]));
      const reordered = event.moduleIds
        .map((id) => lookup.get(id))
        .filter((m): m is { moduleId: string; name: string } => m !== undefined);
      return { ...view, modules: reordered };
    }
    default: { const _n: never = event; return view; }
  }
}

export function syllabusFrom(
  syllabusId: string,
  events: ReadonlyArray<SyllabusEvent>,
): SyllabusView {
  return events.reduce(project, emptyView(syllabusId));
}
