```typescript
export type LabEvent =
  | { type: "LabRegistered"; labId: string; name: string; seats: number }
  | { type: "LabBooked"; labId: string; learner: string; at: string }
  | { type: "LabReleased"; labId: string; learner: string }
  | { type: "LabDecommissioned"; labId: string };

export type LabView = Readonly<{
  labId: string;
  name: string;
  seats: number;
  decommissioned: boolean;
  occupants: ReadonlyArray<string>;
}>;

export type LabBoard = Readonly<{ labs: Readonly<Record<string, LabView>> }>;

export const emptyView: LabBoard = { labs: {} };

function mapLab(board: LabBoard, labId: string, fn: (v: LabView) => LabView): LabBoard {
  const current = board.labs[labId];
  if (!current) return board;
  return { labs: { ...board.labs, [labId]: fn(current) } };
}

export function project(board: LabBoard, event: LabEvent): LabBoard {
  switch (event.type) {
    case "LabRegistered":
      return {
        labs: {
          ...board.labs,
          [event.labId]: { labId: event.labId, name: event.name, seats: event.seats, decommissioned: false, occupants: [] },
        },
      };
    case "LabBooked":
      return mapLab(board, event.labId, (lab) =>
        lab.occupants.includes(event.learner) || lab.occupants.length >= lab.seats
          ? lab
          : { ...lab, occupants: [...lab.occupants, event.learner] });
    case "LabReleased":
      return mapLab(board, event.labId, (lab) => ({
        ...lab,
        occupants: lab.occupants.filter((l) => l !== event.learner),
      }));
    case "LabDecommissioned":
      return mapLab(board, event.labId, (lab) => ({ ...lab, decommissioned: true }));
    default: { const _n: never = event; return board; }
  }
}

export function labBoardFrom(events: ReadonlyArray<LabEvent>): LabBoard {
  return events.reduce(project, emptyView);
}
```

Tag every stored snapshot with its schema version. At load time, run upgraders in order until you reach CURRENT_VERSION, then assert the final shape. The stream itself never needs rewriting.

```typescript
export type Snapshot<S> = { version: number; state: S };

export type EnrolmentV1 = { id: string; learner: string };
export type EnrolmentV2 = { id: string; learner: string; course: string };
export type EnrolmentV3 = {
  id: string;
  learner: string;
  course: string;
  status: "registered" | "confirmed" | "withdrawn";
};

export type CurrentEnrolment = EnrolmentV3;
export const CURRENT_VERSION = 3;

class UpgradeError extends Error {}

function v1Tov2(s: EnrolmentV1): EnrolmentV2 {
  return { ...s, course: "unknown" };
}

function v2Tov3(s: EnrolmentV2): EnrolmentV3 {
  return { ...s, status: "registered" };
}

export function upgradeSnapshot(snap: Snapshot<unknown>): Snapshot<CurrentEnrolment> {
  let v = snap.version;
  let s: unknown = snap.state;
  if (v === 1) { s = v1Tov2(s as EnrolmentV1); v = 2; }
  if (v === 2) { s = v2Tov3(s as EnrolmentV2); v = 3; }
  if (v !== CURRENT_VERSION) throw new UpgradeError("UNSUPPORTED");
  const out = s as CurrentEnrolment;
  if (!out.id || !out.learner) throw new UpgradeError("SHAPE");
  return { version: v, state: out };
}
```

```typescript
export type Snapshot<S> = { version: number; state: S };

export type CourseV1 = { id: string; title: string };
export type CourseV2 = { id: string; title: string; capacity: number };
export type CourseV3 = {
  id: string;
  title: string;
  capacity: number;
  status: "draft" | "open" | "scheduled" | "closed";
};

export type CurrentCourse = CourseV3;
export const CURRENT_VERSION = 3;

export class UpgradeError extends Error {}

function v1Tov2(s: CourseV1): CourseV2 {
  return { ...s, capacity: 0 };
}

function v2Tov3(s: CourseV2): CourseV3 {
  return { ...s, status: "draft" };
}

type UpgradeStep = { from: number; to: number; run: (raw: unknown) => unknown };

const pipeline: ReadonlyArray<UpgradeStep> = [
  { from: 1, to: 2, run: (raw) => v1Tov2(raw as CourseV1) },
  { from: 2, to: 3, run: (raw) => v2Tov3(raw as CourseV2) },
];

export function upgradeSnapshot(snap: Snapshot<unknown>): Snapshot<CurrentCourse> {
  let version = snap.version;
  let state: unknown = snap.state;
  for (const step of pipeline) {
    if (version === step.from) {
      state = step.run(state);
      version = step.to;
    }
  }
  if (version !== CURRENT_VERSION) throw new UpgradeError("UNKNOWN_VERSION");
  const current = state as CurrentCourse;
  if (!current.id || !current.title) throw new UpgradeError("SHAPE_MISMATCH");
  return { version, state: current };
}
