```typescript
export type Snapshot<S> = { version: number; state: S };

export type CertificateV1 = { id: string; learner: string };
export type CertificateV2 = { id: string; learner: string; courseId: string };
export type CertificateV3 = {
  id: string;
  learner: string;
  courseId: string;
  issuedAt: string | null;
};
export type CertificateV4 = {
  id: string;
  learner: string;
  courseId: string;
  issuedAt: string | null;
  revoked: boolean;
};

export type CurrentCertificate = CertificateV4;
export const CURRENT_VERSION = 4;

export class UpgradeError extends Error {}

function v1Tov2(s: CertificateV1): CertificateV2 {
  return { ...s, courseId: "" };
}

function v2Tov3(s: CertificateV2): CertificateV3 {
  return { ...s, issuedAt: null };
}

function v3Tov4(s: CertificateV3): CertificateV4 {
  return { ...s, revoked: false };
}

export function loadCertificateSnapshot(
  snap: Snapshot<unknown>,
): Snapshot<CurrentCertificate> {
  let version = snap.version;
  let state: unknown = snap.state;
  while (version < CURRENT_VERSION) {
    if (version === 1) {
      state = v1Tov2(state as CertificateV1);
      version = 2;
      continue;
    }
    if (version === 2) {
      state = v2Tov3(state as CertificateV2);
      version = 3;
      continue;
    }
    if (version === 3) {
      state = v3Tov4(state as CertificateV3);
      version = 4;
      continue;
    }
    throw new UpgradeError("UNSUPPORTED_VERSION");
  }
  if (version !== CURRENT_VERSION) throw new UpgradeError("VERSION_MISMATCH");
  const current = state as CurrentCertificate;
  if (!current.id || !current.learner) throw new UpgradeError("SHAPE");
  return { version, state: current };
}
