  switch (event.type) {
    case "CohortFormed":
      return { status: "forming", id: event.id, members: [] };
    case "LearnerAdmitted":
      if (state.status !== "forming") return state;
      return { ...state, members: [...state.members, event.learner] };
    default: { const _n: never = event; return state; }
  }
}

export class DomainError extends Error {}
export class ConcurrencyConflict extends Error {}

export function decide(c: CohortCommand, s: CohortState): CohortEvent[] {
  switch (c.type) {
    case "form":
      if (s.status !== "none") throw new DomainError("EXISTS");
      return [{ type: "CohortFormed", id: c.id }];
    case "admit":
      if (s.status !== "forming") throw new DomainError("NOT_FORMING");
      return [{ type: "LearnerAdmitted", learner: c.learner }];
    default: { const _n: never = c; throw new DomainError("UNKNOWN"); }
  }
}

