  readStream(s: string): Promise<{ events: ReadonlyArray<CohortEvent>; revision: bigint | null }>;
  appendToStream(
    s: string,
    events: ReadonlyArray<CohortEvent>,
    opts: { expectedRevision: ExpectedRevision },
  ): Promise<{ ok: true; nextRevision: bigint } | { ok: false; actualRevision: bigint | null }>;
}

export async function handleCohortCommand(
  store: EventStore,
  streamName: string,
  command: CohortCommand,
): Promise<bigint> {
  const { events, revision } = await store.readStream(streamName);
  const state = events.reduce(evolve, initialState);
  const newEvents = decide(command, state);
  if (newEvents.length === 0) return revision ?? 0n;
  const expectedRevision: ExpectedRevision = revision ?? "no_stream";
  const result = await store.appendToStream(streamName, newEvents, { expectedRevision });
  if (!result.ok) throw new ConcurrencyConflict("REVISION_MISMATCH");
  return result.nextRevision;
}
