```typescript
export type LectureEvent =
  | { type: "LectureScheduled"; id: string; title: string }
  | { type: "LearnerCheckedIn"; lectureId: string; learner: string };

export type EventEnvelope<E> = { position: bigint; event: E };

export interface CheckpointStore {
  read(name: string): Promise<bigint | null>;
  write(name: string, position: bigint): Promise<void>;
}

export interface EventSource<E> {
  readFrom(position: bigint): AsyncIterable<EventEnvelope<E>>;
}

export interface ReadModelStore<V, E> {
  load(): Promise<V>;
  project(view: V, event: E): Promise<V>;
  save(view: V): Promise<void>;
}

export async function runLectureSubscription<V>(
  subscriptionName: string,
  source: EventSource<LectureEvent>,
  checkpoints: CheckpointStore,
  readModel: ReadModelStore<V, LectureEvent>,
): Promise<void> {
  const last = await checkpoints.read(subscriptionName);
  const start: bigint = last ?? 0n;
  let view: V = await readModel.load();
  for await (const { position, event } of source.readFrom(start)) {
    view = await readModel.project(view, event);
    await readModel.save(view);
    await checkpoints.write(subscriptionName, position);
  }
}
```

The runner reads the last checkpoint, resumes from that position, and for each event applies the projection, saves the view, then advances the checkpoint. The order matters: a crash between apply and checkpoint write replays at most one event, which the projection must tolerate.

```typescript
import { Effect } from "effect";

export type SyllabusEvent =
  | { type: "SyllabusCreated"; syllabusId: string; title: string }
  | { type: "SyllabusModuleAdded"; syllabusId: string; moduleId: string; name: string };

export type EventEnvelope<E> = { position: bigint; event: E };

export interface CheckpointStore {
  read(name: string): Promise<bigint | null>;
  write(name: string, position: bigint): Promise<void>;
}

export interface EventSource<E> {
  readFrom(position: bigint): AsyncIterable<EventEnvelope<E>>;
}

export interface Projection<V, E> {
  load(): Promise<V>;
  apply(view: V, event: E): Promise<V>;
  save(view: V): Promise<void>;
}

export const runSyllabusSubscription = <V>(
  name: string,
  source: EventSource<SyllabusEvent>,
  checkpoints: CheckpointStore,
  projection: Projection<V, SyllabusEvent>,
) =>
  Effect.gen(function* () {
    const last = yield* Effect.promise(() => checkpoints.read(name));
    const start: bigint = last ?? 0n;
    let view = yield* Effect.promise(() => projection.load());
    const run = async (): Promise<void> => {
      for await (const { position, event } of source.readFrom(start)) {
        view = await projection.apply(view, event);
        await projection.save(view);
        await checkpoints.write(name, position);
      }
    };
    yield* Effect.promise(() => run());
  });
