export type SubmissionView = Readonly<{
  activeDrafts: number;
  turnedInCount: number;
}>;

export const emptyView: SubmissionView = { activeDrafts: 0, turnedInCount: 0 };

export function project(view: SubmissionView, event: SubmissionEvent): SubmissionView {
  switch (event.type) {
    case "SubmissionStarted":
      return { ...view, activeDrafts: view.activeDrafts + 1 };
    case "AttachmentAttached":
      return view;
    case "SubmissionTurnedIn":
      return {
        activeDrafts: Math.max(0, view.activeDrafts - 1),
        turnedInCount: view.turnedInCount + 1,
      };
    default: { const _n: never = event; return view; }
  }
}

export interface ViewStore {
  load(): Promise<SubmissionView>;
  save(view: SubmissionView): Promise<void>;
}

export async function catchUp(
  name: string,
  source: EventSource,
  checkpoints: CheckpointStore,
  store: ViewStore,
): Promise<void> {
  const last = await checkpoints.read(name);
  let view = await store.load();
  for await (const { position, event } of source.readFromStream(last ?? 0n)) {
    view = project(view, event);
    await store.save(view);
    await checkpoints.write(name, position);
  }
}
