  switch (event.type) {
    case "AssignmentAssigned":
      return { status: "assigned", id: event.id, learner: event.learner };
    case "AssignmentSubmitted":
      if (state.status !== "assigned") return state;
      return { status: "submitted", id: state.id, learner: state.learner, submittedAt: event.at };
    case "AssignmentGraded":
      if (state.status !== "submitted") return state;
      return { status: "graded", id: state.id, learner: state.learner, score: event.score };
    default: { const _n: never = event; return state; }
  }
}

export function aggregate(events: ReadonlyArray<AssignmentEvent>): AssignmentState {
  return events.reduce(when, initialState);
