  | { type: "EnrolmentConfirmed"; version: 1; at: string };

export type CurrentEvent =
  | { type: "EnrolmentRegistered"; version: 2; id: string; learner: string; course: string }
  | { type: "EnrolmentConfirmed"; version: 1; at: string };

export class UnknownEventError extends Error {}

function assertRaw(raw: unknown): asserts raw is RawEvent {
  if (typeof raw !== "object" || raw === null) throw new UnknownEventError("NOT_OBJECT");
}

export function upcast(raw: unknown): CurrentEvent {
  assertRaw(raw);
  switch (raw.type) {
    case "EnrolmentRegistered":
      if (raw.version === 1) {
        return {
          type: "EnrolmentRegistered",
          version: 2,
          id: raw.id,
          learner: raw.studentId,
          course: raw.course,
        };
      }
      return raw;
    case "EnrolmentConfirmed":
      return raw;
    default: {
      const _n: never = raw;
      throw new UnknownEventError("UNKNOWN_TYPE");
    }
  }
}

export function upcastAll(rawEvents: ReadonlyArray<unknown>): CurrentEvent[] {
  return rawEvents.map(upcast);
}

// A read-time aggregate helper: upcast raw events, then fold into a simple view.
export type EnrolmentView = Readonly<{ id: string; learner: string; course: string; confirmed: boolean }>;

export const emptyView: EnrolmentView = { id: "", learner: "", course: "", confirmed: false };

export function project(view: EnrolmentView, event: CurrentEvent): EnrolmentView {
  switch (event.type) {
    case "EnrolmentRegistered":
      return { id: event.id, learner: event.learner, course: event.course, confirmed: false };
    case "EnrolmentConfirmed":
      return { ...view, confirmed: true };
    default: { const _n: never = event; return view; }
  }
}

export function enrolmentViewFrom(rawEvents: ReadonlyArray<unknown>): EnrolmentView {
  return upcastAll(rawEvents).reduce(project, emptyView);
}
