```typescript
export type DiscussionEvent =
  | { type: "DiscussionOpened"; id: string; topic: string }
  | { type: "PostAppended"; id: string; author: string; body: string }
  | { type: "DiscussionArchived"; id: string };

export type DiscussionView = Readonly<{
  threads: Readonly<Record<string, { topic: string; posts: number; archived: boolean }>>;
}>;

export const emptyView: DiscussionView = { threads: {} };

export function project(view: DiscussionView, event: DiscussionEvent): DiscussionView {
  switch (event.type) {
    case "DiscussionOpened":
      return { threads: { ...view.threads, [event.id]: { topic: event.topic, posts: 0, archived: false } } };
    case "PostAppended": {
      const thread = view.threads[event.id];
      if (!thread) return view;
      return { threads: { ...view.threads, [event.id]: { ...thread, posts: thread.posts + 1 } } };
    }
    case "DiscussionArchived": {
      const thread = view.threads[event.id];
      if (!thread) return view;
      return { threads: { ...view.threads, [event.id]: { ...thread, archived: true } } };
    }
    default: { const _n: never = event; return view; }
  }
}

export type Envelope = { revision: bigint; event: DiscussionEvent };

export interface EventStoreReader {
  readForward(from: bigint, batchSize: number): Promise<ReadonlyArray<Envelope>>;
}

export interface ReadModelStore {
  wipe(): Promise<void>;
  get(): Promise<DiscussionView>;
  put(view: DiscussionView): Promise<void>;
}

export interface RebuildOptions {
  from: bigint;
  batchSize: number;
  wipeFirst: boolean;
  onProgress?: (cursor: bigint, processed: number) => void;
}

export async function rebuild(
  reader: EventStoreReader,
  store: ReadModelStore,
  options: RebuildOptions,
): Promise<void> {
  if (options.wipeFirst) await store.wipe();
  let cursor: bigint = options.from;
  let processed = 0;
  let view: DiscussionView = options.from === 0n ? emptyView : await store.get();
  while (true) {
    const batch = await reader.readForward(cursor, options.batchSize);
    if (batch.length === 0) break;
    for (const { revision, event } of batch) {
      view = project(view, event);
      cursor = revision + 1n;
      processed = processed + 1;
    }
    await store.put(view);
    if (options.onProgress) options.onProgress(cursor, processed);
  }
}
