export type CohortEvent =
  | { type: "CohortFormed"; id: string; capacity: number }
  | { type: "LearnerAdmitted"; id: string; learner: string }
  | { type: "CohortSealed"; id: string };

export type CohortSummary = Readonly<{
  cohorts: Readonly<Record<string, { capacity: number; members: ReadonlyArray<string>; sealed: boolean }>>;
}>;

export const emptyView: CohortSummary = { cohorts: {} };

export function project(view: CohortSummary, event: CohortEvent): CohortSummary {
  switch (event.type) {
    case "CohortFormed":
      return { cohorts: { ...view.cohorts, [event.id]: { capacity: event.capacity, members: [], sealed: false } } };
    case "LearnerAdmitted": {
      const cohort = view.cohorts[event.id];
      if (!cohort) return view;
      return { cohorts: { ...view.cohorts, [event.id]: { ...cohort, members: [...cohort.members, event.learner] } } };
    }
    case "CohortSealed": {
      const cohort = view.cohorts[event.id];
      if (!cohort) return view;
      return { cohorts: { ...view.cohorts, [event.id]: { ...cohort, sealed: true } } };
    }
    default: { const _n: never = event; return view; }
  }
}

export interface Reader {
  readBatch(from: bigint, size: number): Promise<ReadonlyArray<{ revision: bigint; event: CohortEvent }>>;
}

export interface CursorStore {
  load(): Promise<bigint>;
  save(cursor: bigint): Promise<void>;
}

export interface ViewStore {
  wipe(): Promise<void>;
  save(view: CohortSummary): Promise<void>;
}

export async function rebuildCohort(
  reader: Reader,
  cursorStore: CursorStore,
  viewStore: ViewStore,
  batchSize: number,
): Promise<CohortSummary> {
  const startCursor = await cursorStore.load();
  if (startCursor === 0n) await viewStore.wipe();
  let cursor = startCursor;
  let view: CohortSummary = emptyView;
  while (true) {
    const batch = await reader.readBatch(cursor, batchSize);
    if (batch.length === 0) break;
    for (const { revision, event } of batch) {
      view = project(view, event);
      cursor = revision + 1n;
    }
    await viewStore.save(view);
    await cursorStore.save(cursor);
  }
  return view;
}
