```typescript
export type AssignmentState =
  | { status: "none" }
  | { status: "turnedIn"; id: string; learner: string; at: string }
  | { status: "retracted"; id: string; reason: string }
  | { status: "graded"; id: string; learner: string; score: number };

export type AssignmentCommand =
  | { type: "turnIn"; id: string; learner: string; at: string }
  | { type: "retract"; reason: string }
  | { type: "grade"; score: number };

export type AssignmentEvent =
  | { type: "AssignmentTurnedIn"; id: string; learner: string; at: string }
  | { type: "AssignmentRetracted"; reason: string }
  | { type: "AssignmentGraded"; score: number };

export class AssignmentError extends Error {
  constructor(public readonly code: string) {
    super(code);
    this.name = "AssignmentError";
  }
}

export const initialState: AssignmentState = { status: "none" };

export function decide(command: AssignmentCommand, state: AssignmentState): AssignmentEvent[] {
  switch (command.type) {
    case "turnIn":
      if (state.status !== "none") throw new AssignmentError("ALREADY_TURNED_IN");
      return [{ type: "AssignmentTurnedIn", id: command.id, learner: command.learner, at: command.at }];
    case "retract":
      if (state.status !== "turnedIn") throw new AssignmentError("NOT_TURNED_IN");
      return [{ type: "AssignmentRetracted", reason: command.reason }];
    case "grade":
      if (state.status === "retracted") throw new AssignmentError("RETRACTED");
      if (state.status !== "turnedIn") throw new AssignmentError("NOT_TURNED_IN");
      if (command.score < 0 || command.score > 100) throw new AssignmentError("SCORE_OUT_OF_RANGE");
      return [{ type: "AssignmentGraded", score: command.score }];
    default: {
      const _n: never = command;
      throw new AssignmentError("UNKNOWN_COMMAND");
    }
  }
}

export function evolve(state: AssignmentState, event: AssignmentEvent): AssignmentState {
  switch (event.type) {
    case "AssignmentTurnedIn":
      return { status: "turnedIn", id: event.id, learner: event.learner, at: event.at };
    case "AssignmentRetracted":
      if (state.status !== "turnedIn") return state;
      return { status: "retracted", id: state.id, reason: event.reason };
    case "AssignmentGraded":
      if (state.status !== "turnedIn") return state;
      return { status: "graded", id: state.id, learner: state.learner, score: event.score };
    default: {
      const _n: never = event;
      return state;
    }
  }
}
